  1	import { type FC, useContext, useState } from 'react';
  2	import { useNavigate } from 'react-router-dom-v5-compat';
  3	import { CreateOverviewContext } from 'src/overview/hooks/OverviewContext';
  4	import { useForkliftTranslation } from 'src/utils/i18n';
  5	
  6	import LoadingSuspend from '@components/LoadingSuspend';
  7	import type { V1beta1ForkliftController } from '@kubev2v/types';
  8	import { ChartDonut } from '@patternfly/react-charts';
  9	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
 10	
 11	import { useVmMigrationsDataPoints } from '../hooks/useVmMigrationsDataPoints';
 12	import { ChartColors } from '../utils/colors';
 13	import { navigateToHistoryTab } from '../utils/navigate';
 14	import { TimeRangeOptions } from '../utils/timeRangeOptions';
 15	import type { ChartDatum } from '../utils/types';
 16	
 17	import HeaderActions from './CardHeaderActions';
 18	
 19	type VmMigrationsDonutCardProps = {
 20	  obj?: V1beta1ForkliftController;
 21	  loaded?: boolean;
 22	  loadError?: unknown;
 23	};
 24	
 25	const VmMigrationsDonutCard: FC<VmMigrationsDonutCardProps> = () => {
 26	  const { t } = useForkliftTranslation();
 27	  const { data, setData } = useContext(CreateOverviewContext);
 28	  const selectedRange = data?.vmMigrationsDonutSelectedRange ?? TimeRangeOptions.All;
 29	  const setSelectedRange = (range: TimeRangeOptions) => {
 30	    setData({
 31	      ...data,
 32	      vmMigrationsDonutSelectedRange: range,
 33	    });
 34	  };
 35	  const [hoveredIndex, setHoveredIndex] = useState<number | null>(null);
 36	  const navigate = useNavigate();
 37	  const {
 38	    loaded,
 39	    loadError,
 40	    obj,
 41	    total,
 42	    totalCanceledCount,
 43	    totalFailedCount,
 44	    totalRunningCount,
 45	    totalSucceededCount,
 46	  } = useVmMigrationsDataPoints(selectedRange, true);
 47	
 48	  const colorScale =
 49	    total === 0
 50	      ? [ChartColors.Empty]
 51	      : [ChartColors.Executing, ChartColors.Failure, ChartColors.Success, ChartColors.Canceled];
 52	
 53	  const highlightColor =
 54	    hoveredIndex !== null && hoveredIndex >= 0 && hoveredIndex < colorScale.length
 55	      ? colorScale[hoveredIndex]
 56	      : ChartColors.Success;
 57	
 58	  return (
 59	    <Card>
 60	      <CardHeader
 61	        actions={{
 62	          actions: (
 63	            <HeaderActions
 64	              selectedTimeRange={selectedRange}
 65	              setSelectedTimeRange={setSelectedRange}
 66	              showAll
 67	            />
 68	          ),
 69	        }}
 70	      >
 71	        <CardTitle className="forklift-title">{t('Virtual machines')}</CardTitle>
 72	      </CardHeader>
 73	      <CardBody className="forklift-overview__status-migration pf-v6-u-display-flex pf-v6-u-align-items-center pf-v6-u-flex-direction-column">
 74	        <div className="forklift-overview__status-migration-donut">
 75	          <LoadingSuspend obj={obj} loaded={loaded} loadError={loadError}>
 76	            <ChartDonut
 77	              ariaDesc={t('Donut chart with VM migration statistics')}
 78	              colorScale={colorScale}
 79	              constrainToVisibleArea
 80	              data={
 81	                total === 0
 82	                  ? [{ x: 'Empty state', y: 1 }]
 83	                  : ([
 84	                      { x: t('running'), y: totalRunningCount },
 85	                      { x: t('failed'), y: totalFailedCount },
 86	                      { x: t('succeeded'), y: totalSucceededCount },
 87	                      { x: t('canceled'), y: totalCanceledCount },
 88	                    ] as ChartDatum[])
 89	              }
 90	              labels={({ datum }: { datum: ChartDatum }) =>
 91	                total === 0
 92	                  ? (undefined as unknown as string)
 93	                  : `${t('{{count}} VM migration', { count: datum.y })}
 94	                        ${datum.x}`
 95	              }
 96	              title={`${totalSucceededCount ?? '0'}`}
 97	              subTitle={t('Migrated')}
 98	              innerRadius={88}
 99	              events={[
100	                {
101	                  eventHandlers: {
102	                    onClick: () => {
103	                      const statusMap = ['Running', 'Failed', 'Succeeded', 'Canceled'];
104	                      const status = statusMap[hoveredIndex!];
105	                      navigateToHistoryTab({ navigate, selectedRange, status });
106	                    },
107	                    onMouseOut: () => {
108	                      setHoveredIndex(null);
109	                      return [
110	                        {
111	                          mutation: () => ({ active: false }),
112	                          target: 'labels',
113	                        },
114	                      ];
115	                    },
116	                    onMouseOver: (_, props: { index: number }) => {
117	                      setHoveredIndex(props.index);
118	                      return [
119	                        {
120	                          mutation: () => ({ active: true }),
121	                          target: 'labels',
122	                        },
123	                      ];
124	                    },
125	                  },
126	                  target: 'data',
127	                },
128	              ]}
129	              style={{
130	                data: {
131	                  cursor: 'pointer',
132	                  stroke: ({ index }) => (hoveredIndex === index ? highlightColor : ''),
133	                  strokeWidth: ({ index }) => (hoveredIndex === index ? 2 : 1),
134	                },
135	              }}
136	            />
137	          </LoadingSuspend>
138	        </div>
139	      </CardBody>
140	    </Card>
141	  );
142	};
143	
144	export default VmMigrationsDonutCard;

